\begin{equation}
\boxed{
\nabla^T_a\nabla^{T\,a}\phi
+
\frac{\partial V_T}{\partial \phi}
+
\mathcal{C}_{RT}
+
\mathcal{C}_{\tau}
=
0 .
}
\end{equation}

\paragraph{Interpretation.}
The Trawinistic field equation combines kinetic propagation, TZP potential response, curvature coupling, and torsion-localized correction.
